// Calculate date range for idea generation
// Uses config values for thresholds

const thresholdsConfig = $input.first().json;
const ideasConfig = thresholdsConfig.ideas || {};

// Get thresholds from config
const minRelevanceScore = ideasConfig.min_relevance_for_idea || 80;
const minFeasibility = ideasConfig.min_feasibility || 50;
const minImpact = ideasConfig.min_impact || 50;
const lookbackDays = ideasConfig.lookback_days || 7;

const now = new Date();

const periodEnd = new Date(now);
periodEnd.setUTCHours(23, 59, 59, 999);

const periodStart = new Date(now);
periodStart.setUTCDate(periodStart.getUTCDate() - lookbackDays);
periodStart.setUTCHours(0, 0, 0, 0);

// Format dates for SQL query
const formatDateSQL = (d) => d.toISOString();

console.log(`Using thresholds from config: minRelevanceScore=${minRelevanceScore}, minFeasibility=${minFeasibility}, minImpact=${minImpact}, lookbackDays=${lookbackDays}`);

return [{
  json: {
    periodStartSQL: formatDateSQL(periodStart),
    periodEndSQL: formatDateSQL(periodEnd),
    generatedAt: now.toISOString(),
    minRelevanceScore,
    _thresholds: {
      minRelevanceScore,
      minFeasibility,
      minImpact,
      lookbackDays
    }
  }
}];

// Merge insights with period data and check if we have any
const insights = $input.all().map(item => item.json);
const periodData = $('Calculate Period').first().json;

// Filter out empty results (when query returns no rows)
const validInsights = insights.filter(i => i.id);

if (validInsights.length === 0) {
  return [{
    json: {
      ...periodData,
      insights: [],
      insightCount: 0,
      hasInsights: false
    }
  }];
}

return [{
  json: {
    ...periodData,
    insights: validInsights,
    insightCount: validInsights.length,
    hasInsights: true
  }
}];

// Cluster insights by primary topic/theme
// Groups related insights together for idea generation
const data = $input.first().json;
const insights = data.insights || [];
const thresholds = data._thresholds || {};

// Group insights by primary topic (first topic in array)
const clusters = {};

for (const insight of insights) {
  const topics = insight.topics || [];
  const primaryTopic = topics[0] || 'general';

  if (!clusters[primaryTopic]) {
    clusters[primaryTopic] = {
      topic: primaryTopic,
      insights: [],
      allTopics: new Set(),
      totalScore: 0
    };
  }

  clusters[primaryTopic].insights.push(insight);
  clusters[primaryTopic].totalScore += insight.freedom_relevance_score;

  // Track all topics across cluster
  for (const t of topics) {
    clusters[primaryTopic].allTopics.add(t);
  }
}

// Convert to array and sort by average score
const clusterArray = Object.values(clusters).map(c => ({
  topic: c.topic,
  insights: c.insights,
  insightCount: c.insights.length,
  avgScore: Math.round(c.totalScore / c.insights.length),
  relatedTopics: Array.from(c.allTopics)
})).sort((a, b) => b.avgScore - a.avgScore);

// Only process clusters with at least 1 insight
// Return as separate items for loop processing
const items = clusterArray.map(cluster => ({
  json: {
    cluster,
    _periodData: {
      generatedAt: data.generatedAt,
      periodStartSQL: data.periodStartSQL,
      periodEndSQL: data.periodEndSQL
    },
    _thresholds: thresholds
  }
}));

return items.length > 0 ? items : [{ json: { noValidClusters: true, _thresholds: thresholds } }];

// STUB: IdeaSynthesizer Agent
// Simulates Claude API response for project idea generation
// Replace with real HTTP Request to Claude API when ready

const input = $input.first().json;
const cluster = input.cluster;
const periodData = input._periodData;
const thresholds = input._thresholds || {};

// Skip if no valid cluster
if (input.noValidClusters) {
  return [{
    json: {
      content: [{ type: 'text', text: JSON.stringify({ skip: true, reason: 'No valid clusters' }) }],
      _periodData: periodData,
      _cluster: null,
      _skip: true,
      _thresholds: thresholds
    }
  }];
}

const insights = cluster.insights || [];
const topic = cluster.topic;
const relatedTopics = cluster.relatedTopics || [];

// Collect all insight IDs for this cluster
const derivedFromInsightIds = insights.map(i => i.id);

// Collect all citations from cluster insights
const allCitations = [];
for (const insight of insights) {
  if (insight.citations && Array.isArray(insight.citations)) {
    allCitations.push(...insight.citations);
  }
}
const uniqueCitations = [...new Set(allCitations)];

// Generate stub project idea based on cluster content
const topicDisplayNames = {
  'bitcoin': 'Bitcoin & Payments',
  'zk': 'Zero Knowledge Technology',
  'censorship-resistance': 'Censorship Resistance',
  'comms': 'Secure Communications',
  'payments': 'Payment Systems',
  'identity': 'Identity & Privacy',
  'privacy': 'Privacy Tools',
  'surveillance': 'Anti-Surveillance',
  'activism': 'Activism Tools',
  'sovereignty': 'Digital Sovereignty'
};

const topicName = topicDisplayNames[topic] || topic;
const insightTitles = insights.slice(0, 3).map(i => i.title).join('; ');
const insightTldrs = insights.slice(0, 3).map(i => i.tldr).join(' ');

// Generate scores based on cluster quality
const avgScore = cluster.avgScore || 80;
const feasibilityScore = Math.min(100, Math.max(40, 60 + Math.floor(Math.random() * 30)));
const impactScore = Math.min(100, Math.max(40, avgScore - 10 + Math.floor(Math.random() * 20)));

const ideaOutput = {
  problem_statement: `Based on ${cluster.insightCount} signals in ${topicName}, there is a clear need for improved tooling. Key observations: ${insightTldrs.substring(0, 400)}...`,
  threat_model: `Adversaries include state-level actors with network monitoring capabilities, platform operators with content moderation powers, and sophisticated attackers targeting ${topicName.toLowerCase()} infrastructure. Users require protection against traffic analysis, metadata correlation, and targeted deanonymization attacks.`,
  affected_groups: [
    'Activists in regions with internet censorship',
    'Journalists protecting sources',
    'Human rights organizations',
    `Users of ${topicName.toLowerCase()} tools under surveillance`
  ],
  proposed_solution: `Develop a ${topicName.toLowerCase()} enhancement that addresses the gaps identified in recent signals. The solution should focus on: (1) improving usability for non-technical users, (2) adding offline/low-bandwidth support, (3) implementing defense-in-depth against the threat model described. Key insights driving this: ${insightTitles}.`,
  mvp_scope: `Phase 1: Build a proof-of-concept that demonstrates the core ${topic} functionality with basic UI. Include: CLI interface, configuration file support, basic documentation, and integration tests. Target: usable by technical early adopters within first release.`,
  misuse_risks: `This tool could potentially be misused for: (1) evading legitimate law enforcement in non-authoritarian contexts, (2) coordinating harmful activities under cover of privacy, (3) spreading misinformation without accountability. Mitigations: implement transparency reporting, add voluntary identity binding options, and include clear usage guidelines.`,
  feasibility_score: feasibilityScore,
  impact_score: impactScore,
  technical_dependencies: [
    'Cryptographic libraries (libsodium or equivalent)',
    'Networking stack with proxy support',
    'Cross-platform runtime (Rust or Go preferred)'
  ],
  suggested_stack: [
    'Rust for core components',
    'TypeScript for any web interfaces',
    'SQLite for local storage',
    'libp2p for P2P networking'
  ],
  prior_art: [
    'Tor Project',
    'Signal Protocol',
    'Briar Messenger',
    'Lokinet'
  ],
  open_questions: [
    'What is the minimum viable UX for non-technical users?',
    'How to handle key management without trusted third parties?',
    'What jurisdictions should be prioritized for initial deployment?',
    'How to fund ongoing development sustainably?'
  ]
};

// Format as Claude API response structure
return [{
  json: {
    content: [{
      type: 'text',
      text: JSON.stringify(ideaOutput)
    }],
    _periodData: periodData,
    _cluster: cluster,
    _derivedFromInsightIds: derivedFromInsightIds,
    _citations: uniqueCitations,
    _topic: topic,
    _thresholds: thresholds
  }
}];

